// Calculate messaging drift score
// Compares current state to initial_messaging captured at launch

const launchData = $('Load Active Launches').item.json;
const currentHomepage = $('Get Current Homepage').item.json;
const homepageChanges = $('Count Homepage Changes').item.json;
const pricingChanges = $('Count Pricing Changes').item.json;

const initial = launchData.initial_messaging || {};
const current = currentHomepage || {};

// Simple drift calculation based on content hash and structural changes
let driftScore = 0;

// Check if content hash changed
if (initial.content_hash && current.content_hash && initial.content_hash !== current.content_hash) {
  driftScore += 0.3;
}

// Check if H1 changed significantly
if (initial.h1_text && current.h1_text) {
  const similarity = calculateSimilarity(initial.h1_text, current.h1_text);
  driftScore += (1 - similarity) * 0.3;
} else if (initial.h1_text !== current.h1_text) {
  driftScore += 0.2;
}

// Factor in number of changes
const changeCount = parseInt(homepageChanges.homepage_change_count) || 0;
if (changeCount >= 5) driftScore += 0.3;
else if (changeCount >= 3) driftScore += 0.2;
else if (changeCount >= 1) driftScore += 0.1;

// Normalize to 0-1
driftScore = Math.min(1, Math.max(0, driftScore));

function calculateSimilarity(str1, str2) {
  const words1 = str1.toLowerCase().split(/\s+/);
  const words2 = str2.toLowerCase().split(/\s+/);
  const set1 = new Set(words1);
  const set2 = new Set(words2);
  const intersection = [...set1].filter(x => set2.has(x)).length;
  const union = new Set([...set1, ...set2]).size;
  return intersection / union;
}

return [{
  json: {
    launch_id: launchData.launch_id,
    company_id: launchData.company_id,
    launch_title: launchData.launch_title,
    weeks_since_launch: Math.floor(launchData.current_weeks),
    messaging_drift_score: Math.round(driftScore * 100) / 100,
    homepage_change_count: parseInt(homepageChanges.homepage_change_count) || 0,
    pricing_change_count: parseInt(pricingChanges.pricing_change_count) || 0
  }
}];

// Summary node
const allItems = $('Record Observation').all();
const emittedItems = $('Emit Signal').all();

return [{
  json: {
    run_completed_at: new Date().toISOString(),
    launches_observed: allItems.length,
    signals_emitted: emittedItems.length,
    signal_ids: emittedItems.map(i => i.json.signal_id).filter(Boolean)
  }
}];
